import React from 'react';
import './home.css';
import logo from './assets/logo.png';

function Home() {
  return (
    <div className="home">
      <div className="logo-container">
        <img src={logo} alt="Logo" className="logo" />
      </div>
      <div className="text-in-the-main">
        <p className='description'>
          " La donnee devient"
        </p>
      </div>
    </div>
  );
}

export default Home;
